installer-gui-script.script:
function installationCheck() {
    if (system.files.fileExistsAtPath('/Applications/OmiibaConnect.app')) {
        my.result.title = 'Update Omiiba Connect';
        my.result.message = 'Version VERSION_PLACEHOLDER will replace the app in Applications. You do not need to remove the old copy first — the installer will quit Omiiba Connect and update in place.';
    } else {
        my.result.title = 'Install Omiiba Connect';
        my.result.message = 'Version VERSION_PLACEHOLDER will be installed in Applications.';
    }
    my.result.type = 'Install';
    return true;
}
